-- Supabase seed for pregenerated Sudoku puzzles
-- Run this in Supabase SQL Editor after creating your project.

create extension if not exists pgcrypto;

create table if not exists public.puzzles (
  id uuid primary key default gen_random_uuid(),
  puzzle_board jsonb not null,
  solution_board jsonb not null,
  difficulty text not null check (difficulty in ('Easy','Medium','Hard','Expert','Master')),
  puzzle_rating integer not null check (puzzle_rating > 0),
  given_count smallint not null check (given_count between 0 and 81),
  generation_method text not null default 'pregenerated_json',
  puzzle_hash text not null unique,
  created_at timestamptz not null default now()
);

create index if not exists idx_puzzles_difficulty_rating
  on public.puzzles (difficulty, puzzle_rating);

create index if not exists idx_puzzles_rating
  on public.puzzles (puzzle_rating);

-- Keep the solution_board protected. Do not add a public SELECT policy on puzzles.
alter table public.puzzles enable row level security;

insert into public.puzzles (
  puzzle_board,
  solution_board,
  difficulty,
  puzzle_rating,
  given_count,
  generation_method,
  puzzle_hash
)
