on conflict (puzzle_hash) do nothing;

-- Public-safe puzzle fetch: returns the puzzle, but not the solution.
create or replace function public.get_random_puzzle(p_difficulty text default null)
returns table (
  id uuid,
  puzzle_board jsonb,
  difficulty text,
  puzzle_rating integer,
  given_count smallint
)
language sql
security definer
set search_path = public
as $$
  select p.id, p.puzzle_board, p.difficulty, p.puzzle_rating, p.given_count
  from public.puzzles p
  where p_difficulty is null or p.difficulty = p_difficulty
  order by random()
  limit 1;
$$;

grant execute on function public.get_random_puzzle(text) to anon, authenticated;
